-- ============================================
-- Legislacao full-site: dr-fernando-maximo / Camara Dados Abertos / projetos_lei
-- Coverage ampliado parcial: Lote A autoria principal Camara
-- ============================================
-- Fonte oficial: Camara dos Deputados - Dados Abertos
--   https://dadosabertos.camara.leg.br/api/v2/deputados/220610
--   https://dadosabertos.camara.leg.br/api/v2/proposicoes/{id}
--   https://dadosabertos.camara.leg.br/api/v2/proposicoes/{id}/autores
--
-- Artefato de auditoria:
--   fonte interna de curadoria
--
-- Coverage:
--   coverage_id    = dr-fernando-maximo-camara-autoria-principal-ampliado-parcial-lote-a-20260506
--   coverage_scope = inventario_ampliado_parcial_camara_autoria_principal_lote_a_20260506
--
-- Filtro factual: das 100 rows Camara legacy existentes, somente 34
-- foram marcadas com coverage_id porque a API oficial confirmou
-- idDeputado=220610, tipo Deputado(a), ordemAssinatura=1.
-- 66 rows permanecem sem coverage por coautoria/sem autoria verificavel.
--
-- Esta migration NAO escreve em legislacao_mandato_executivo.
-- Esta migration NAO insere, deleta ou trunca rows.
-- ============================================

DO $$
DECLARE
  cand_id uuid;
  total_pl int;
  target_present int;
  target_with_other_coverage int;
  lme_count int;
BEGIN
  SELECT id INTO cand_id FROM candidatos WHERE slug = 'dr-fernando-maximo';

  IF cand_id IS NULL THEN
    RAISE NOTICE 'dr-fernando-maximo: candidato ausente neste banco local/CI minimo; coverage Camara pulado';
    RETURN;
  END IF;

  SELECT count(*) INTO total_pl FROM projetos_lei WHERE candidato_id = cand_id;
  IF total_pl <> 100 THEN
    RAISE EXCEPTION 'Pre-condicao dr-fernando-maximo: esperadas 100 rows legacy em projetos_lei, encontradas %', total_pl;
  END IF;

  SELECT count(*) INTO target_present
  FROM projetos_lei
  WHERE candidato_id = cand_id
    AND fonte = 'Camara'
    AND proposicao_id_api IN ('2579645', '2598438', '2579665', '2579660', '2579659', '2579658', '2579653', '2579651', '2579650', '2579649', '2568815', '2562325', '2561501', '2554259', '2543197', '2568787', '2562324', '2553628', '2568506', '2565361', '2562320', '2561450', '2568505', '2562315', '2560476', '2568504', '2563058', '2562310', '2579648', '2573075', '2604840', '2574049', '2573074', '2561483');
  IF target_present <> 34 THEN
    RAISE EXCEPTION 'Pre-condicao dr-fernando-maximo: esperadas 34 rows alvo Camara presentes, encontradas %', target_present;
  END IF;

  SELECT count(*) INTO target_with_other_coverage
  FROM projetos_lei
  WHERE candidato_id = cand_id
    AND proposicao_id_api IN ('2579645', '2598438', '2579665', '2579660', '2579659', '2579658', '2579653', '2579651', '2579650', '2579649', '2568815', '2562325', '2561501', '2554259', '2543197', '2568787', '2562324', '2553628', '2568506', '2565361', '2562320', '2561450', '2568505', '2562315', '2560476', '2568504', '2563058', '2562310', '2579648', '2573075', '2604840', '2574049', '2573074', '2561483')
    AND coverage_id IS NOT NULL
    AND coverage_id <> 'dr-fernando-maximo-camara-autoria-principal-ampliado-parcial-lote-a-20260506';
  IF target_with_other_coverage <> 0 THEN
    RAISE EXCEPTION 'Pre-condicao dr-fernando-maximo: % rows alvo ja tem coverage_id divergente', target_with_other_coverage;
  END IF;

  SELECT count(*) INTO lme_count FROM legislacao_mandato_executivo WHERE candidato_id = cand_id;
  IF lme_count <> 0 THEN
    RAISE EXCEPTION 'Pre-condicao dr-fernando-maximo: legislacao_mandato_executivo deve permanecer 0, encontrado %', lme_count;
  END IF;
END $$;

